    if self._audio_buffer is None:
        self.notify("Nothing to play — generate first", severity="warning")
        return
    import tempfile, soundfile as sf
    with tempfile.NamedTemporaryFile(suffix=".wav", delete=False) as f:
        sf.write(f.name, self._audio_buffer.astype(np.float32), self._sample_rate)
        tmp = f.name
    if sys.platform == "darwin":
        subprocess.Popen(["afplay", tmp])
    elif sys.platform == "win32":
        subprocess.Popen(["start", "/min", "wmplayer", tmp], shell=True)
    else:
        subprocess.Popen(["xdg-open", tmp])
    self.notify(f"Playing...")

